#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        int arr[n];
        for(int i=0;i<n;++i) scanf("%d",&arr[i]);
        int left=0, zeroCnt=0, best=0;
        for(int right=0; right<n; ++right){
            if(arr[right]==0) ++zeroCnt;
            while(zeroCnt>1){
                if(arr[left]==0) --zeroCnt;
                ++left;
            }
            int len = right-left+1;
            if(len>best) best=len;
        }
        printf("%d\n",best);
    }
    return 0;
}

