import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        left = 0
        zero_cnt = 0
        best = 0
        for right, val in enumerate(arr):
            if val == 0:
                zero_cnt += 1
            while zero_cnt > 1:
                if arr[left] == 0:
                    zero_cnt -= 1
                left += 1
            best = max(best, right - left + 1)
        out.append(str(best))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

